mapper.select:
SELECT tenant_id
FROM user_tenant_access
WHERE user_id = #{userId}

SELECT COUNT(*)
FROM user
WHERE email = #{email}
  AND id != #{userId}

mapper.delete:
DELETE FROM user_tenant_access
WHERE user_id = #{userId}
  AND tenant_id = #{tenantId}

mapper.update:
UPDATE user
name = #{name}, email = #{email}, role = #{role}, status = #{status}, permissions = #{permissions}, read_only = #{readOnly}, password = #{password}, secondary_password = #{secondaryPassword},
WHERE id = #{id}

UPDATE user_tenant_access
account_permissions = #{accountPermissions}, process_permissions = #{processPermissions},
WHERE id = #{id}
